@OptIn(ExperimentalAbiValidation::class)
fun Project.configureAbiValidation() {
    afterEvaluate {
        val kotlinExtension = extensions.findByType<KotlinProjectExtension>() ?: return@afterEvaluate

        kotlinExtension.abiValidation {
            referenceDumpDir.set(layout.projectDirectory.dir("api"))
            filters {
                exclude {
                    annotatedWith.add("coil3.annotation.InternalCoilApi")
                }
            }
            binariesSource.set(BinariesSource.MAIN_COMPILATION)
        }
    }
}

actual fun Image.asPainter(
    context: PlatformContext,
    filterQuality: FilterQuality,
): Painter = when (this) {
    is BitmapImage -> BitmapPainter(
        image = bitmap.asImageBitmap(),
        filterQuality = filterQuality,
    )
    is DrawableImage -> DrawablePainter(
        drawable = asDrawable(context.resources).mutate(),
    )
    else -> ImagePainter(this)
}

private fun updateState(state: State) {
    val previous = stateFlow.value
    val current = transform(state)
    stateFlow.value = current
    painter = maybeNewCrossfadePainter(previous, current, contentScale) ?: current.painter

    // Manually forget and remember the old/new painters.
    if (previous.painter !== current.painter) {
        (previous.painter as? RememberObserver)?.onForgotten()
        (current.painter as? RememberObserver)?.onRemembered()
    }

    // Notify the state listener.
    onState?.invoke(current)
}

private fun ImageResult.toState() = when (this) {
    is SuccessResult -> State.Success(
        painter = image.asPainter(request.context, filterQuality),
        result = this,
    )
    is ErrorResult -> State.Error(
        painter = image?.asPainter(request.context, filterQuality),
        result = this,
    )
}

private fun lazyDrawSizeFlow(): Flow<Size> {
    var drawSizeFlow = drawSizeFlow
    if (drawSizeFlow == null) {
        drawSizeFlow = MutableSharedFlow(
            replay = 1,
            onBufferOverflow = DROP_OLDEST,
        )
        val drawSize = drawSize
        if (drawSize.isSpecified) {
            drawSizeFlow.tryEmit(drawSize)
        }
        this.drawSizeFlow = drawSizeFlow
    }
    return drawSizeFlow
}

override suspend fun size(): Size {
    if (latestConstraints.isZero) {
        var continuation: Continuation<Unit>? = null
        try {
            suspendCancellableCoroutine<Unit> {
                continuation = it
                continuations.add(it)
            }
        } finally {
            continuations.remove(continuation)
        }
    }
    return latestConstraints.toSize()
}

fun setConstraints(constraints: Constraints) {
    // Cache the latest constraints.
    latestConstraints = constraints
    if (!constraints.isZero) {
        val c = continuations
        if (c.isNotEmpty()) {
            continuations = mutableListOf()
            c.forEach { it.resume(Unit) }
        }
    }
}

override fun DrawScope.onDraw() {
    scale(
        scaleX = image.width.let { if (it > 0) size.width / it else 1f },
        scaleY = image.height.let { if (it > 0) size.height / it else 1f },
        pivot = Offset.Zero,
    ) {
        image.draw(drawContext.canvas.nativeCanvas)
    }
}

