actual fun Image.asPainter(
    context: PlatformContext,
    filterQuality: FilterQuality,
): Painter = when (this) {
    is BitmapImage -> BitmapPainter(
        image = toBitmap().asComposeImageBitmap(),
        filterQuality = filterQuality,
    )
    else -> ImagePainter(this)
}

actual override fun draw(canvas: Canvas) {
    val paint = lazyPaint ?: run {
        Paint()
            .apply { color = this@ColorImage.color }
            .also { lazyPaint = it }
    }
    if (width >= 0 && height >= 0) {
        canvas.drawRect(0f, 0f, width.toFloat(), height.toFloat(), paint)
    } else {
        canvas.drawPaint(paint)
    }
}

fun getExifData(
    mimeType: String?,
    source: BufferedSource,
    strategy: ExifOrientationStrategy,
): ExifData {
    if (strategy.supports(mimeType, source)) {
        val exifInterface = ExifInterface(ExifInterfaceInputStream(source.peek().inputStream()))
        return ExifData(exifInterface.isFlipped, exifInterface.rotationDegrees)
    } else {
        return ExifData.NONE
    }
}

override suspend fun fetch(): FetchResult {
    val path = data.pathSegments.drop(1).joinToString("/")

    return SourceFetchResult(
        source = ImageSource(
            source = options.context.assets.open(path).source().buffer(),
            fileSystem = options.fileSystem,
            metadata = AssetMetadata(path),
        ),
        mimeType = MimeTypeMap.getMimeTypeFromUrl(path),
        dataSource = DataSource.DISK,
    )
}

@VisibleForTesting
    internal fun isMusicThumbnailUri(data: Uri): Boolean {
        if (data.authority != MediaStore.AUTHORITY) return false
        val segments = data.pathSegments
        val size = segments.size
        return size >= 3 && segments[size - 3] == "audio" && segments[size - 2] == "albums"
    }

@JvmOverloads
actual fun Image.toBitmap(
    width: Int,
    height: Int,
): Bitmap {
    var bitmapConfig: Bitmap.Config? = null

    if (this is BitmapImage) {
        bitmapConfig = bitmap.config
    }

    return toBitmap(width, height, bitmapConfig ?: Bitmap.Config.ARGB_8888)
}

fun Image.toBitmap(
    width: Int,
    height: Int,
    config: Bitmap.Config,
): Bitmap {
    if (this is BitmapImage &&
        bitmap.width == width &&
        bitmap.height == height &&
        bitmap.config == config
    ) {
        return bitmap
    }

    return createBitmap(width, height, config).applyCanvas(::draw)
}

override fun key(data: Uri, options: Options): String? {
    if (data.scheme == SCHEME_ANDROID_RESOURCE) {
        // 'android.resource' uris can change if night mode is enabled/disabled.
        return "$data:${options.context.resources.configuration.nightMode}"
    }
    return null
}

internal actual fun getDisposable(
    request: ImageRequest,
    job: Deferred<ImageResult>,
): Disposable {
    if (request.target is ViewTarget<*>) {
        return request.target.view.requestManager.getDisposable(job)
    } else {
        return OneShotDisposable(job)
    }
}

private fun ImageRequest.resolveSizeResolver(): SizeResolver {
    if (target is ViewTarget<*>) {
        // CENTER and MATRIX scale types should be decoded at the image's original size.
        val view = target.view
        if (view is ImageView && view.scaleType.let { it == CENTER || it == MATRIX }) {
            return SizeResolver.ORIGINAL
        } else {
            return ViewSizeResolver(view)
        }
    } else {
        // Fall back to the image's source dimensions.
        return SizeResolver.ORIGINAL
    }
}

private fun isBitmapConfigValidMainThread(
    request: ImageRequest,
    size: Size,
): Boolean {
    val validForTransformations = request.transformations.isEmpty() ||
        request.bitmapConfig in VALID_TRANSFORMATION_CONFIGS
    val validForHardware = !request.bitmapConfig.isHardware ||
        (
            isConfigValidForHardware(request, request.bitmapConfig) &&
            hardwareBitmapService.allowHardwareMainThread(size)
        )
    return validForTransformations && validForHardware
}
